fn binary_search(xs: & Vec<i64>, target: i64) -> i64 {
    let mut lo: i64 = 0;
    let mut hi: i64 = (xs.len() as i64).wrapping_sub(1);
    while lo <= hi {
        let mid: i64 = (lo).wrapping_add(hi) / 2;
        if xs[(mid) as usize] == target {
            return mid;
        }
        if xs[(mid) as usize] < target {
            lo = (mid).wrapping_add(1);
        } else {
            hi = (mid).wrapping_sub(1);
        }
    }
    return -1;
}

