fn mandelbrot_iters(cx: f64, cy: f64, max_iter: i64) -> i64 {
    let mut x: f64 = 0.0;
    let mut y: f64 = 0.0;
    let mut i: i64 = 0;
    while i < max_iter {
        let x2: f64 = x * x;
        let y2: f64 = y * y;
        if x2 + y2 > 4.0 {
            return i;
        }
        y = 2.0 * x * y + cy;
        x = x2 - y2 + cx;
        i = (i).wrapping_add(1);
    }
    return max_iter;
}

fn in_mandelbrot(cx: f64, cy: f64) -> bool {
    return mandelbrot_iters(cx, cy, 100) == 100;
}

fn main() {
    println!("{}", mandelbrot_iters(0.0, 0.0, 100));
    println!("{}", if in_mandelbrot(0.5, 0.5) { String::from("True") } else { String::from("False") });
}
