fn sqrt_newton(x: f64) -> f64 {
    if x <= 0.0 {
        return 0.0;
    }
    let mut guess: f64 = x;
    let mut i: i64 = 0;
    while i < 50 {
        guess = 0.5 * (guess + x / guess);
        i = (i).wrapping_add(1);
    }
    return guess;
}

