fn sum_list(xs: & Vec<i64>) -> i64 {
    let mut total: i64 = 0;
    for i in 0..xs.len() as i64 {
        total = (total).wrapping_add(xs[(i) as usize]);
    }
    return total;
}

fn max_element(xs: & Vec<i64>) -> i64 {
    let mut best: i64 = xs[(0) as usize];
    for i in 0..xs.len() as i64 {
        if xs[(i) as usize] > best {
            best = xs[(i) as usize];
        }
    }
    return best;
}

fn main() {
    let mut xs: Vec<i64> = vec![3, 1, 4, 1, 5, 9, 2, 6, 5, 3, 5];
    println!("{} {}", sum_list(&mut xs), max_element(&mut xs));
