fn triangle_closed(n: i64) -> i64 {
    return (n).wrapping_mul((n).wrapping_add(1)) / 2;
}

fn triangle_loop(n: i64) -> i64 {
    let mut total: i64 = 0;
    let mut i: i64 = 1;
    while i <= n {
        total = (total).wrapping_add(i);
        i = (i).wrapping_add(1);
    }
    return total;
}

fn main() {
    println!("{}", triangle_closed(10));
    println!("{}", triangle_loop(10));
}
